use std::collections::HashMap;

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut ans = Vec::new();
    for query in queries {
        let li = query[0] as usize;
        let ri = query[1] as usize;
        let threshold = query[2];
        let subarray = &nums[li..=ri];

        let mut freq = HashMap::new();
        for &num in subarray {
            *freq.entry(num).or_insert(0) += 1;
        }

        let mut candidates: Vec<(i64, i64)> = freq.into_iter()
            .filter(|&(_, count)| count >= threshold)
            .collect();

        if candidates.is_empty() {
            ans.push(-1);
        } else {
            candidates.sort_by(|a, b| {
                if a.1 != b.1 {
                    b.1.cmp(&a.1)
                } else {
                    a.0.cmp(&b.0)
                }
            });
            ans.push(candidates[0].0);
        }
    }
    ans
}
